from test_public import database, sql


def test_explosion_multiplies_each_nested_edge():
    db = database([("kit", "module", 2), ("module", "bolt", 3)])
    assert db.execute(sql("explode_work_order.sql"), {"root_sku": "kit"}).fetchall() == [
        ("module", 2, 1), ("bolt", 6, 2)
    ]


def test_leaf_requirements_sum_independent_paths():
    db = database([
        ("kit", "left", 2), ("kit", "right", 3),
        ("left", "screw", 5), ("right", "screw", 7),
    ])
    assert db.execute(
        sql("required_materials.sql"), {"root_sku": "kit", "build_count": 1}
    ).fetchall() == [("screw", 31)]
